import uuid
import time
import hashlib
import secrets
import json
import threading


class InMemoryDatabase:
    """Thread-safe in-memory database for development."""

    def __init__(self):
        self._users = {}
        self._tokens = {}
        self._user_data = {}
        self._lock = threading.RLock()
        self._seed_data()

    def _hash_password(self, password):
        return hashlib.sha256(password.encode()).hexdigest()

    def _seed_data(self):
        """Seed with sample data."""
        users = [
            ("admin", "admin@example.com", "admin123", "Admin User"),
            ("john_doe", "john@example.com", "password123", "John Doe"),
            ("jane_smith", "jane@example.com", "password456", "Jane Smith"),
        ]
        for username, email, password, full_name in users:
            user_id = str(uuid.uuid4())
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": self._hash_password(password),
                "full_name": full_name,
                "created_at": int(time.time()),
            }
            self._user_data[user_id] = {
                "preferences": json.dumps({"theme": "dark", "language": "en"}),
                "activity": json.dumps({"last_login": int(time.time()), "login_count": 42}),
                "profile": json.dumps({"bio": f"Hello, I'm {full_name}", "avatar_url": ""}),
            }
        print(f"Database seeded with {len(self._users)} users.")

    def find_user_by_username(self, username):
        with self._lock:
            for user in self._users.values():
                if user["username"] == username:
                    return user.copy()
        return None

    def get_user(self, user_id):
        with self._lock:
            user = self._users.get(user_id)
            return user.copy() if user else None

    def create_user(self, username, email, password, full_name):
        with self._lock:
            # Check uniqueness
            for user in self._users.values():
                if user["username"] == username:
                    return None, "Username already exists"
                if user["email"] == email:
                    return None, "Email already exists"

            user_id = str(uuid.uuid4())
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": self._hash_password(password),
                "full_name": full_name,
                "created_at": int(time.time()),
            }
            self._user_data[user_id] = {
                "preferences": json.dumps({"theme": "light", "language": "en"}),
                "activity": json.dumps({"last_login": None, "login_count": 0}),
                "profile": json.dumps({"bio": "", "avatar_url": ""}),
            }
            return user_id, "User created successfully"

    def verify_password(self, username, password):
        user = self.find_user_by_username(username)
        if user and user["password_hash"] == self._hash_password(password):
            return user
        return None

    def create_token(self, user_id, username):
        with self._lock:
            token = secrets.token_hex(32)
            self._tokens[token] = {
                "user_id": user_id,
                "username": username,
                "created_at": int(time.time()),
                "expires_at": int(time.time()) + 3600,  # 1 hour
            }
            return token

    def validate_token(self, token):
        with self._lock:
            token_data = self._tokens.get(token)
            if token_data and token_data["expires_at"] > int(time.time()):
                return token_data.copy()
            if token_data and token_data["expires_at"] <= int(time.time()):
                del self._tokens[token]
            return None

    def revoke_token(self, token):
        with self._lock:
            if token in self._tokens:
                del self._tokens[token]
                return True
            return False

    def list_users(self, page=1, page_size=10):
        with self._lock:
            all_users = list(self._users.values())
            total = len(all_users)
            start = (page - 1) * page_size
            end = start + page_size
            return [u.copy() for u in all_users[start:end]], total

    def get_user_data(self, user_id, data_type=None):
        with self._lock:
            data = self._user_data.get(user_id, {})
            if data_type and data_type in data:
                return {data_type: data[data_type]}
            return data.copy()


